SELECT 'profiles_policies' AS audit_section, policyname, cmd, roles, qual, with_check FROM pg_policies WHERE schemaname = 'public' AND tablename = 'profiles' ORDER BY policyname; SELECT 'profiles_columns' AS audit_section, column_name, data_type, is_nullable, column_default FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'profiles' AND column_name IN ('id','role','is_active','is_approved','deleted_at','created_at') ORDER BY ordinal_position; SELECT 'profiles_triggers' AS audit_section, trigger_name, event_manipulation, action_timing, action_statement FROM information_schema.triggers WHERE event_object_schema = 'public' AND event_object_table = 'profiles' ORDER BY trigger_name; SELECT 'account_action_rpc_access' AS audit_section, p.proname, has_function_privilege('anon', p.oid, 'EXECUTE') AS anon_can_execute, has_function_privilege('authenticated', p.oid, 'EXECUTE') AS authenticated_can_execute FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = 'public' AND p.proname IN ('admin_deactivate_profiles_v1','admin_restore_profiles_v1','admin_list_deactivated_profiles_v1') ORDER BY p.proname; SELECT 'profiles_summary' AS audit_section, count(*) FILTER (WHERE deleted_at IS NULL) AS visible_profiles, count(*) FILTER (WHERE deleted_at IS NOT NULL) AS deactivated_profiles, count(*) FILTER (WHERE deleted_at IS NULL AND COALESCE(is_active,false) AND COALESCE(is_approved,false)) AS approved_active_profiles FROM public.profiles;
